using System.ComponentModel;
using Microsoft.Extensions.AI;
using ModelContextProtocol.Server;

/// <summary>
/// MCP prompt templates for content summarization.
/// </summary>
[McpServerPromptType]
public static class SummarizationPrompts
{
    [McpServerPrompt, Description("Summarize the provided content into a concise paragraph.")]
    public static ChatMessage Summarize(
        [Description("The content to summarize")] string content) =>
        new(ChatRole.User, $"Summarize the following content into a concise paragraph:\n\n{content}");

    [McpServerPrompt, Description("Summarize content with a specific focus area or angle.")]
    public static IList<ChatMessage> SummarizeWithFocus(
        [Description("The content to summarize")] string content,
        [Description("The specific angle or topic to focus on")] string focus) =>
    [
        new(ChatRole.System, $"You are a summarization assistant. Focus specifically on aspects related to: {focus}"),
        new(ChatRole.User, $"Summarize the following content:\n\n{content}")
    ];
}

